import{_ as r,c as e,o as a,a4 as t}from"./chunks/framework.HaEZziQ1.js";const b=JSON.parse('{"title":"Tauri框架入门","description":"","frontmatter":{},"headers":[],"relativePath":"Document/跨平台桌面端开发/Tauri框架/Tauri框架入门.md","filePath":"Document/跨平台桌面端开发/Tauri框架/Tauri框架入门.md","lastUpdated":null}'),i={name:"Document/跨平台桌面端开发/Tauri框架/Tauri框架入门.md"},l=t('<h1 id="tauri框架入门" tabindex="-1">Tauri框架入门 <a class="header-anchor" href="#tauri框架入门" aria-label="Permalink to &quot;Tauri框架入门&quot;">​</a></h1><p>官网：<a href="https://tauri.app/zh-cn/" target="_blank" rel="noreferrer">https://tauri.app/zh-cn/</a></p><p>GitHub开源地址：<a href="https://github.com/tauri-apps/tauri" target="_blank" rel="noreferrer">https://github.com/tauri-apps/tauri</a></p><h2 id="tauri-系列教程" tabindex="-1">Tauri+系列教程 <a class="header-anchor" href="#tauri-系列教程" aria-label="Permalink to &quot;Tauri+系列教程&quot;">​</a></h2><p><strong>Tauri+系列教程</strong>：<a href="https://github.com/lencx/tauri-tutorial/discussions?discussions_q=label%3A%22Tauri+%E7%B3%BB%E5%88%97%22" target="_blank" rel="noreferrer">lencx/tauri-tutorial · Discussions · GitHub</a></p><hr><p>一文读懂 Tauri：<a href="https://github.com/lencx/tauri-tutorial/discussions/23" target="_blank" rel="noreferrer">https://github.com/lencx/tauri-tutorial/discussions/23</a></p><h2 id="tauri-概览" tabindex="-1">Tauri 概览 <a class="header-anchor" href="#tauri-概览" aria-label="Permalink to &quot;Tauri 概览&quot;">​</a></h2><ul><li><p>利用操作系统提供的 WebView 来呈现界面，来避免打包体积过大。一般套壳空应用打包后的体积控制在 3M 左右。而 <a href="https://www.electronjs.org/" target="_blank" rel="noreferrer">Electron</a> 会将整个 <a href="https://www.chromium.org/" target="_blank" rel="noreferrer">Chromium</a> 打包进应用（安装包体积几十兆起步）。因为系统差异，所以使用自带 Webview 会存在兼容性问题，但是应该朝前看，IE 浏览器都被微软自家宣布死亡了。</p></li><li><p>相比 Electron 有更低的内存占用，更小的体积，更少的线程，系统调用等。了解更多 <a href="https://tauri.app/v1/references/benchmarks" target="_blank" rel="noreferrer">Tauri 基准测试</a>。</p></li><li><p>安装包是跨平台的，目前支持 Mac，Windows，Linux 等，未来也会支持 iOS/iPadOS 和 Android 等，跨平台打包可以使用官方提供的 <a href="https://github.com/tauri-apps/tauri-action" target="_blank" rel="noreferrer">Tauri GitHub Action</a>，虽然是跨端，但是一些特定于平台的代码还是需要借助于插件或者自行实现，并在真机上进行功能验证，否则可能出现行为和预期不一致。</p></li><li><p>提供内置签名以确保应用自动更新时可以安全安装，相关配置请查看 <a href="https://tauri.app/v1/guides/distribution/updater" target="_blank" rel="noreferrer">Tauri Updater</a>。</p></li><li><p>使用 <a href="https://tauri.app/v1/guides/features/icons" target="_blank" rel="noreferrer">tauri icons</a> 命令生成自定义应用图标（要求：格式为 PNG 的正方形图片）。</p></li><li><p>应用更安全，Tauri 在架构层做了很多安全处理（比如：通过配置来约束 Tauri 访问系统文件，网络请求，剪贴板等）。</p><ul><li>源代码更安全，Tauri 只提供二进制文件。而不是像 Electron 的 <a href="https://www.electronjs.org/docs/latest/tutorial/asar-archives" target="_blank" rel="noreferrer">ASAR</a> 文件。</li><li>数据更安全，隔离模式会对前后端（Webview 和 Tauri Core）通信数据进行加密传输。</li></ul></li><li><p>前端使用 HTML、CSS、JavaScript 来构建界面（也可以使用前端主流技术，如：<a href="https://vitejs.dev/" target="_blank" rel="noreferrer">vite</a>，<a href="https://reactjs.org/" target="_blank" rel="noreferrer">react</a>，<a href="https://vuejs.org/" target="_blank" rel="noreferrer">vue</a>，<a href="https://svelte.dev/" target="_blank" rel="noreferrer">svelte</a> 等）。后端目前使用 Rust，未来也可能会支持其他类型语言（如：Go、Nim、Python、Csharp 等）。</p></li><li><p>强大的系统交互能力，支持配置全局快捷键，系统菜单，系统托盘，文件读写，命令行，系统信息，剪贴板等。Rust 给 Tauri 带来了无限的想象力，Rust 可以做的事情，Tauri 理论上也可以做（欢迎自行尝试，可能也有做不了的）。</p></li><li><p>Tauri Window</p><p>支持多种配置。磨砂透明背景，无边框功能则需要借助的两个插件（支持 Windows 和 macOS，Linux 暂不支持）：</p><ul><li><a href="https://github.com/tauri-apps/window-shadows" target="_blank" rel="noreferrer">window-shadows</a> - 为窗口添加阴影。</li><li><a href="https://github.com/tauri-apps/window-vibrancy" target="_blank" rel="noreferrer">window-vibrancy</a> - 为窗口配置磨砂效果。</li></ul></li><li><p>支持创建多个窗口以及为新窗口脚本注入，但是脚本注入需要在 rust 端创建窗口，使用 <code>WindowBuilder::new</code> 中的 <code>initialization_script</code> 来加载脚本。</p></li><li><p>通过提供的 <a href="https://tauri.app/v1/guides/features/command" target="_blank" rel="noreferrer">Tauri Command</a>，可以从 Web 应用程序调用 Rust 函数。通过 <a href="https://tauri.app/v1/guides/features/events" target="_blank" rel="noreferrer">Tauri Events</a>（<code>emit</code> 和 <code>listen</code>）可以在前后端之间传递消息，它与 Tauri Command 有类似性。</p></li><li><p>...</p></li></ul><p>综合来看，<a href="https://tauri.app/v1/api/js/" target="_blank" rel="noreferrer">Tauri JS API</a> 确实提供了很多便捷 API 供前端使用，但是有些底层方法并未暴露，而 <a href="https://docs.rs/tauri/1.2.0/tauri/" target="_blank" rel="noreferrer">Tauri Rust API</a> 则要强大很多。</p><h2 id="开发问题" tabindex="-1">开发问题 <a class="header-anchor" href="#开发问题" aria-label="Permalink to &quot;开发问题&quot;">​</a></h2><h3 id="资源-文档" tabindex="-1">资源 &amp; 文档 <a class="header-anchor" href="#资源-文档" aria-label="Permalink to &quot;资源 &amp; 文档&quot;">​</a></h3><ul><li><a href="https://tauri.app/" target="_blank" rel="noreferrer">Tauri doc</a> - 官方文档，第一参考资料，建议熟读，源码及 issues 可以作为补充。</li><li><a href="https://github.com/tauri-apps/awesome-tauri" target="_blank" rel="noreferrer">Awesome Tauri</a> - 精选的 Tauri 生态系统和社区中最好的东西，包含插件和应用，可以借鉴和学习。</li><li><a href="https://github.com/tauri-apps/tauri/issues" target="_blank" rel="noreferrer">Tauri issues</a> - 质量很高的问题回答，可以解决开发中遇到的大量困惑或报错。如果未搜到，还可以自己上报，执行 <code>cargo tauri info</code> 或 <code>npm run tauri info</code> 可以查看平台和版本信息。</li><li><a href="https://github.com/tauri-apps/tauri/discussions" target="_blank" rel="noreferrer">Tauri discussions</a> - 讨论社区</li><li><a href="https://developer.mozilla.org/en-US/" target="_blank" rel="noreferrer">MDN doc</a> - 很权威的 Web 技术文档，包含 CSS，HTML，JavaScript。</li><li><a href="https://doc.rust-lang.org/book/" target="_blank" rel="noreferrer">Rust doc</a> - Rust 编程语言基本语法学习</li><li><a href="https://www.npmjs.com/" target="_blank" rel="noreferrer">npmjs</a> - 前端生态的包管理网站</li><li><a href="https://crates.io/" target="_blank" rel="noreferrer">crates.io</a> - Rust 生态的包管理网站</li></ul><h3 id="开发准备" tabindex="-1">开发准备 <a class="header-anchor" href="#开发准备" aria-label="Permalink to &quot;开发准备&quot;">​</a></h3><p>编辑器推荐使用 <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code</a>，需要安装的插件：</p><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=tauri-apps.tauri-vscode" target="_blank" rel="noreferrer">Tauri</a> - 对 Tauri 命令和 tauri.conf.json JSON 验证提供支持。</li><li><a href="https://marketplace.visualstudio.com/items?itemName=rust-lang.rust-analyzer" target="_blank" rel="noreferrer">rust-analyzer</a> - 插件提供了对 Rust 编程语言的支持。包含代码提示，类型定义，代码跳转等等。</li><li><a href="https://marketplace.visualstudio.com/items?itemName=serayuzgur.crates" target="_blank" rel="noreferrer">crates</a> - 是 <code>crates.io</code> 依赖项的插件。旨在帮助开发人员在使用 Cargo.toml 时管理依赖项（鼠标悬停 crate 名称可以显示可用版本列表）。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="子窗口不能使用-tauri-api" tabindex="-1">子窗口不能使用 <code>__TAURI__</code> API <a class="header-anchor" href="#子窗口不能使用-tauri-api" aria-label="Permalink to &quot;子窗口不能使用 `__TAURI__` API&quot;">​</a></h3><p>新创建的远程 URL 子窗口无法使用 Tauri API，因为这与 Tauri 架构安全是违背的，以下有两条相关 issues：</p><ul><li>[<a href="https://github.com/tauri-apps/tauri/issues/4837" target="_blank" rel="noreferrer">bug] cant use window.<strong>TAURI</strong> with remote url</a></li><li>[<a href="https://github.com/tauri-apps/tauri/issues/5088" target="_blank" rel="noreferrer">feat] Inject window.<strong>TAURI</strong> in allowed remote URLs</a></li></ul><p>简单概括为：任何与 IPC 相关的问题都触及到了 Tauri 核心，并不能快速解决此类问题，但在 v2，v3 或未来更高的版本会有所改进。Tauri 不会在外部 URL 开的窗口上注入 Tauri API，如果项目没有本地资源，可以通过将 <code>distDir</code> 设置为<code>远程 URL</code> 来解决这个问题，或者在使用的运行时更改它。但这种情况下只有一个外部 URL 能够访问 Tauri API，其实就是修改 tauri.conf.json 中配置的 <code>build.devPath</code>（开发环境） 和 <code>build.distDir</code> （生产环境）字段。</p><h3 id="brownfield-vs-isolation-模式" tabindex="-1">Brownfield vs Isolation 模式 <a class="header-anchor" href="#brownfield-vs-isolation-模式" aria-label="Permalink to &quot;Brownfield vs Isolation 模式&quot;">​</a></h3><p><a href="https://tauri.app/v1/references/architecture/inter-process-communication/brownfield" target="_blank" rel="noreferrer">Brownfield 模式</a>是使用 Tauri 的最简单、最直接的模式，因为它尽可能地与现有的前端项目兼容。但也并非完全兼容（API 未被浏览器广泛支持，Tauri 正在实现中的），请参阅 <a href="https://tauri.app/v1/references/architecture/inter-process-communication/brownfield#incompatibilities" target="_blank" rel="noreferrer">不兼容部分</a>。</p><p><a href="https://tauri.app/v1/references/architecture/inter-process-communication/isolation" target="_blank" rel="noreferrer">Isolation 模式</a>下前端发送到 Tauri Core 之前会被注入的一个安全的应用程序拦截和修改传入的 IPC 消息（使用 <a href="https://developer.mozilla.org/en-US/docs/Web/HTML/Element/iframe" target="_blank" rel="noreferrer">iframe</a> 沙盒隔离，使用浏览器的 <a href="https://developer.mozilla.org/en-US/docs/Web/API/SubtleCrypto" target="_blank" rel="noreferrer">SubtleCrypto</a> 来对数据进行加密。为了确保安全，每次运行应用时都会生成新的密钥），来避免被前端恶意调用。</p><p>总结：所以老项目想使用 Tauri 进行套壳，想快速上线，可以考虑 Brownfield 模式。使用 Isolation 模式则更加安全，通信时消息加解密相比于 Brownfield 模式会存在额外的开销成本，除非高性能要求，否则 <code>AES-GCM</code> 身份验证算法的成本几乎可以忽略不计。</p><h2 id="评价-tauri" tabindex="-1">评价 Tauri <a class="header-anchor" href="#评价-tauri" aria-label="Permalink to &quot;评价 Tauri&quot;">​</a></h2><blockquote><p>在技术群，文章评论区也有一些朋友问过我：”如何看待 Tauri？“，我也只是业余折腾，写过几篇浅显的文章而已。</p></blockquote><p>以我目前的了解来看，觉得它很可能成为下一代跨端（桌面，移动端）方案，但前提是它真的实现了比较易用的移动端绑定（目前还在计划中）。Web 的生态奠定了今天的互联网基础，前端技术又是层出不穷，快速迭代。而 Tauri 想做的事情就是实现 Webview 和系统之间的桥接层（站在巨人的肩膀）。所以跨多少个端，提供什么样的能力是 Tauri 需要考虑的事情，开发应用功能是我们需要考虑的事情。Tauri 未提供的支持，我们也可以通过它的插件机制去扩展。</p><p>————————————————————————————————————————————</p><ul><li>参考教程：<a href="https://www.hellagur.com/2022/09/06/%E5%88%9D%E8%AF%86-Tauri-%E7%AF%87%E4%B8%80%E4%B9%8B%E5%88%9D%E7%AA%A5%E9%97%A8%E5%BE%84/" target="_blank" rel="noreferrer">https://www.hellagur.com/2022/09/06/初识-Tauri-篇一之初窥门径/</a></li><li><a href="https://www.cnblogs.com/xiaoyan2017/p/16812092.html" target="_blank" rel="noreferrer">基于tauri+vue3.x多开窗口|Tauri创建多窗体实践 - xiaoyan2017 - 博客园 (cnblogs.com)</a></li><li><a href="https://juejin.cn/post/7159783024995860494" target="_blank" rel="noreferrer">vue3.js+tauri整合聊天|tauri仿微信|vite3+tauri聊天室 - 掘金 (juejin.cn)</a></li><li>tauri打包桌面应用步骤及配置详解--windows完美打包&amp;mac完美打包：<a href="https://www.cnblogs.com/JokerA/p/15638087.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/JokerA/p/15638087.html</a></li></ul><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h2><p>和Electron相比</p><ul><li>打包更小</li><li>启动更快</li><li>性能更好</li><li>安全性好</li></ul>',33),o=[l];function s(n,u,p,h,c,d){return a(),e("div",null,o)}const m=r(i,[["render",s]]);export{b as __pageData,m as default};
